css:
.wrapper-crm-csat {
  --surface: var(--block-bg-color, #15151A);
  --surface-raised: #1B1B22;
  --ink: var(--color-text, #F4F4F7);
  --muted: var(--color-gray-500, #8A8A96);
  --soft: var(--color-gray-700, #C2C2CC);
  --line: var(--color-gray-200, rgba(255,255,255,0.07));
  --accent: var(--color-primary, #FFD21E);
  --accent-2: var(--color-secondary, #FF3D8B);
  box-sizing: border-box;
  width: 100%;
  max-width: 100%;
  height: 100%;
  container-type: inline-size;
  color: var(--ink);
  font-family: var(--font-stack-primary, 'Inter', system-ui, -apple-system, 'Segoe UI', Roboto, sans-serif);
  font-variant-numeric: tabular-nums;
}

.wrapper-crm-csat .chart-card-csat {
  box-sizing: border-box;
  display: flex;
  flex-direction: column;
  width: 100%;
  max-width: 100%;
  height: 100%;
  min-width: 0;
  min-height: 260px;
  background: var(--surface);
  border: 1px solid var(--line);
  border-radius: 14px;
  padding: 16px 18px;
  box-shadow: 0 1px 0 rgba(255,255,255,0.03) inset, 0 6px 18px rgba(0,0,0,0.5);
  transition: border-color .16s ease, box-shadow .16s ease, background-color .16s ease;
}

.wrapper-crm-csat .chart-card-csat:hover,
.wrapper-crm-csat .chart-card-csat:focus-within {
  background: var(--surface-raised);
  border-color: color-mix(in srgb, var(--accent) 30%, var(--line));
  box-shadow: 0 1px 0 rgba(255,255,255,0.04) inset, 0 10px 26px rgba(0,0,0,0.55);
}

.wrapper-crm-csat .head-csat {
  margin: 0 0 14px;
  min-width: 0;
}

.wrapper-crm-csat .eyebrow-csat {
  display: inline-flex;
  align-items: center;
  gap: 7px;
  max-width: 100%;
  font: 700 11px/1.2 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  letter-spacing: .13em;
  text-transform: uppercase;
  color: var(--soft);
}

.wrapper-crm-csat .eyebrow-csat::before {
  content: "";
  flex: 0 0 auto;
  width: 7px;
  height: 7px;
  border-radius: 50%;
  background: var(--accent);
}

.wrapper-crm-csat .head-csat h3 {
  margin: 8px 0 0;
  font: 800 15px/1.25 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  letter-spacing: -.01em;
  color: var(--ink);
  overflow-wrap: break-word;
}

.wrapper-crm-csat .sub-csat {
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  gap: 6px 14px;
  margin: 6px 0 0;
  font: 500 11.5px/1.4 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  color: var(--muted);
  overflow-wrap: break-word;
}

.wrapper-crm-csat .desc-csat { min-width: 0; }

.wrapper-crm-csat .hint-csat {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  color: var(--soft);
}

.wrapper-crm-csat .hint-csat::before {
  content: "";
  flex: 0 0 auto;
  width: 6px;
  height: 6px;
  border-radius: 50%;
  background: var(--accent-2);
}

.wrapper-crm-csat .canvas-csat {
  flex: 1 1 auto;
  width: 100%;
  max-width: 100%;
  min-width: 0;
  min-height: 220px;
}

.wrapper-crm-csat .empty-csat {
  flex: 1 1 auto;
  display: flex;
  align-items: center;
  justify-content: center;
  min-height: 220px;
  margin: 0;
  padding: 0 12px;
  text-align: center;
  color: var(--muted);
  font: 600 13px/1.4 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
}

.wrapper-crm-csat .empty-csat[hidden] { display: none; }

/* Reflow against the block's OWN cell width (container queries), not the
   viewport. This card is one half of a chart pair; when the pair stacks to a
   single column (<=720px) keep the ECharts canvas at >=220px so it never
   collapses to zero height. Trim padding/type as the cell gets very narrow. */
@container (max-width: 720px) {
  .wrapper-crm-csat .chart-card-csat { padding: 15px 16px; }
  .wrapper-crm-csat .canvas-csat,
  .wrapper-crm-csat .empty-csat { min-height: 220px; }
}
@container (max-width: 640px) {
  .wrapper-crm-csat .chart-card-csat { padding: 14px 15px; }
}
@container (max-width: 420px) {
  .wrapper-crm-csat .chart-card-csat { padding: 13px; }
  .wrapper-crm-csat .head-csat { margin-bottom: 12px; }
  .wrapper-crm-csat .head-csat h3 { font-size: 14px; }
}
@container (max-width: 360px) {
  .wrapper-crm-csat .chart-card-csat { padding: 12px; }
  .wrapper-crm-csat .eyebrow-csat { letter-spacing: .1em; }
  .wrapper-crm-csat .head-csat h3 { font-size: 13.5px; }
  .wrapper-crm-csat .sub-csat { gap: 6px; }
}

@media (prefers-reduced-motion: reduce) {
  .wrapper-crm-csat .chart-card-csat { transition: none; }
}
